import React from 'react';
import { useNavigate } from 'react-router-dom';
import apiClient from '../services/api';

const TestLogin = () => {
  const navigate = useNavigate();

  const handleTestLogin = async (role) => {
    try {
      // Сначала регистрируем тестового пользователя (если не существует)
      const email = `test_${role}@example.com`;
      const password = 'test123';
      
      try {
        // Пробуем зарегистрироваться
        await apiClient.post('/api/auth/register', {
          email: email,
          password: password,
          first_name: role === 'admin' ? 'Тест' : 'Пользователь',
          last_name: role === 'admin' ? 'Админ' : 'Тестов',
          age: 25,
          role: role
        });
      } catch (err) {
        // Если пользователь уже существует - игнорируем
        console.log('User already exists, proceeding to login');
      }

      // Входим
      const response = await apiClient.post('/api/auth/login', {
        email: email,
        password: password
      });

      const { accessToken, user } = response.data;
      
      // Сохраняем токен
      localStorage.setItem('accessToken', accessToken);
      
      // Перенаправляем на главную
      navigate('/products');
      window.location.reload(); // Перезагружаем для обновления контекста
    } catch (error) {
      console.error('Test login error:', error);
      alert('Ошибка при тестовом входе');
    }
  };

  return (
    <div style={styles.container}>
      <h3 style={styles.title}>🔧 Тестовый вход</h3>
      <div style={styles.buttons}>
        <button 
          onClick={() => handleTestLogin('user')}
          style={styles.userButton}
        >
          👤 Войти как Пользователь
        </button>
        <button 
          onClick={() => handleTestLogin('seller')}
          style={styles.sellerButton}
        >
          💼 Войти как Продавец
        </button>
        <button 
          onClick={() => handleTestLogin('admin')}
          style={styles.adminButton}
        >
          👑 Войти как Администратор
        </button>
      </div>
    </div>
  );
};

const styles = {
  container: {
    position: 'fixed',
    bottom: '20px',
    right: '20px',
    backgroundColor: 'white',
    padding: '20px',
    borderRadius: '8px',
    boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
    zIndex: 1000,
    minWidth: '250px'
  },
  title: {
    margin: '0 0 15px 0',
    fontSize: '16px',
    color: '#333',
    textAlign: 'center'
  },
  buttons: {
    display: 'flex',
    flexDirection: 'column',
    gap: '10px'
  },
  userButton: {
    padding: '10px 15px',
    backgroundColor: '#6c757d',
    color: 'white',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '14px'
  },
  sellerButton: {
    padding: '10px 15px',
    backgroundColor: '#ffc107',
    color: '#333',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '14px',
    fontWeight: 'bold'
  },
  adminButton: {
    padding: '10px 15px',
    backgroundColor: '#dc3545',
    color: 'white',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '14px',
    fontWeight: 'bold'
  }
};

export default TestLogin;
